package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.mockito.Mockito.mock;
import static org.mockito.Mockito.when;

import java.lang.reflect.Method;

import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testWithEscape() {
        // Create a mock CSVFormat object
        CSVFormat csvFormat = mock(CSVFormat.class);

        // Define the escape character
        char escape = '\\';

        // Mock the behavior of withEscape method
        when(csvFormat.withEscape(Character.valueOf(escape))).thenReturn(csvFormat);

        // Invoke the withEscape method using reflection
        try {
            Method withEscapeMethod = CSVFormat.class.getDeclaredMethod("withEscape", Character.class);
            withEscapeMethod.setAccessible(true);
            CSVFormat result = (CSVFormat) withEscapeMethod.invoke(csvFormat, Character.valueOf(escape));

            // Assert the result
            assertEquals(csvFormat, result);
        } catch (Exception e) {
            e.printStackTrace();
        }
    }
}
